Set




client.c

#include "pair.h" 
int main() { 
    int x = 1;
    pair_ptr p;
    p = newp(); 
    setp(p, x, x*2);
    free(p);
    return 0;
}





pair.h

#include &lt;stdlib.h&gt;

typedef struct pair *pair_ptr;
pair_ptr newp();
void setp(pair_ptr p, int x, int y);





pair.h

#include "pair.h" 
struct pair { 
    int x, y; 
}; 

pair_ptr newp() { 
    pair_ptr p = malloc(sizeof(struct pair));
    p-&gt;x = 0; 
    p-&gt;y = 0; 
    return p; 
}

void setp(pair_ptr p, int x, int y) { 
    p-&gt;x = x; 
    p-&gt;y = y; 
}





